CREATE PROC [dbo].[TR_DINHMUC_GOVAN_Update2]
( 
	@masp            nvarchar(max), 
	@pcode nvarchar(50),
	@c_level int,
	@selection bit = 0,
	@mact            nvarchar(20), 
	@stt             nvarchar(20), 
	@chitiet         nvarchar(max), 
	@nguyenlieu      nvarchar(max), 
	@dayy_tc         decimal(18, 2)  = 0, 
	@rong_tc         decimal(18, 2)  = 0, 
	@dai_tc          decimal(18, 2)  = 0, 
	@soluong_tc      int            = 0, 
	@m3_tc           decimal(18, 5)  = 0, 
	@dayy_sc         decimal(18, 2)  = 0, 
	@rong_sc         decimal(18, 2)  = 0, 
	@dai_sc          decimal(18, 2)  = 0, 
	@soluong_sc      decimal(18, 2)  = 0,
	@m3_sc           decimal(18, 5)  = 0, 
	@dayy_phoi       decimal(18, 2)  = 0, 
	@ghichu          nvarchar(max), 
	@nguoisua        nvarchar(20), 
	@hinhanh         image          = NULL, 
	@soluong_mong    int            = 0, 
	@kichthuoc_mong  decimal(18, 2)  = 0, 
	@mong1  decimal(18, 2)  = 0, 
	@mong2  decimal(18, 2)  = 0, 
	@veneer_matchinh nvarchar(200)  = NULL, 
	@veneer_matphu   nvarchar(200)  = NULL, 
	@veneer_canhngan int            = 0, 
	@veneer_canhdai  int            = 0,
	@chatluong nvarchar(100) = null,
	@long nvarchar(100) = null,
	@bemat nvarchar(max) = null,
	@chitiet_ghep nvarchar(200) = null,
	@phoi_ghep decimal(18, 2) = 0,
	@t_sort int = 0
)
AS
BEGIN

DECLARE @IsGhep BIT
SET @IsGhep = 0
IF CHARINDEX('THONG', @nguyenlieu) > 0 AND @rong_tc > 61
    SET @IsGhep = 1
IF CHARINDEX('TRAM', @nguyenlieu) > 0 AND @rong_tc > 61
    SET @IsGhep = 1
IF CHARINDEX('DE GAI', @nguyenlieu) > 0 AND @rong_tc > 201
    SET @IsGhep = 1


    UPDATE tr_dinhmuc_govan
	 SET  stt = @stt, 
		 chitiet = @chitiet, 
		 nguyenlieu = @nguyenlieu, 
		 dayy_tc = @dayy_tc, 
		 rong_tc = @rong_tc, 
		 dai_tc = @dai_tc, 
		 soluong_tc = @soluong_tc, 
		 m3_tc = @m3_tc,
		 dayy_sc = @dayy_sc, 
		 rong_sc = @rong_sc, 
		 dai_sc = @dai_sc, 
		 soluong_sc = @soluong_sc,
		 m3_sc = @m3_sc,
		 dayy_phoi = @dayy_phoi, 
		 ghichu = @ghichu, 
		 nguoisua = @nguoisua, 
		 ngaysua = GETDATE(), 
		 hinhanh = @hinhanh, 
		 soluong_mong = @soluong_mong, 
		 kichthuoc_mong = @kichthuoc_mong, 
		 mong1 = @mong1,
		 mong2 = @mong2,
		 veneer_matchinh = @veneer_matchinh, 
		 veneer_matphu = @veneer_matphu, 
		 veneer_canhngan = @veneer_canhngan, 
		 veneer_canhdai = @veneer_canhdai,
		 pcode = @pcode,
		 c_level = @c_level,
		 selection = @selection,
		 chatluong = @chatluong,
		 long = @long,
		 bemat = @bemat,
		 chitiet_ghep = @chitiet_ghep,
		 phoi_ghep = @phoi_ghep,
		 chitiet_ghep2 = @IsGhep,
		 t_sort = @t_sort
    WHERE  masp = @masp
		AND mact = @mact
END","parseAnalysis":{"readsTables":[],"writesTables":["dbo.tr_dinhmuc_govan"],"flags":[],"suggestedTier":"B"},"tablesEnriched":{"dbo.dqt_pallet_chitiet":"dqt_pallet_chitiet","dbo.dqt_thongke_phoi":"dqt_thongke_phoi","dbo.mes_hoso_donhang":"mes_hoso_donhang","dbo.ps_kehoach_donhang":"ps_kehoach_donhang","dbo.ps_kehoach_donhang_trangthai":"ps_kehoach_donhang_trangthai","dbo.tr_bophan":"tr_bophan","dbo.tr_chitiet_hangtrang":"tr_chitiet_hangtrang","dbo.tr_common":"tr_common","dbo.tr_dinhmuc_donggoi":"tr_dinhmuc_donggoi","dbo.tr_dinhmuc_govan":"tr_dinhmuc_govan","dbo.tr_dinhmuc_hangtrang":"tr_dinhmuc_hangtrang","dbo.tr_dinhmuc_ngukim":"tr_dinhmuc_ngukim","dbo.tr_dinhmuc_son":"tr_dinhmuc_son","dbo.tr_dinhmuc_son_new":"tr_dinhmuc_son_new","dbo.tr_dinhmuc_son_theomau":"tr_dinhmuc_son_theomau","dbo.tr_dondathang":"tr_dondathang","dbo.tr_dondathang_chitiet":"tr_dondathang_chitiet","dbo.tr_gridview_column":"tr_gridview_column","dbo.tr_luutrinh_sanxuat":"tr_luutrinh_sanxuat","dbo.tr_material":"tr_material","dbo.tr_nguyenlieu_gva":"tr_nguyenlieu_gva","dbo.tr_order":"tr_order","dbo.tr_order_detail":"tr_order_detail","dbo.tr_sanpham":"tr_sanpham","dbo.tr_tinhtrang_fsc":"tr_tinhtrang_fsc"}}
